1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	export function quote(items: { type: string }[], context: QuoteContext): number {
14	  const itemsBasePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
15	  return itemsBasePremium + POLICY_FEE;
16	}
17	
18	export function claim(): unknown {
19	  return undefined;
20	}
