61	describe("Claim Office - claim (payout)", () => {
62	  // Standard reimbursement minus deductible
63	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
64	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
65	
66	  // High-enchantment clause
67	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
68	
69	  // Dragon-material clause
70	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
71	
72	  // Conflict: 50% rule wins over dragon
73	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
74	
75	  // Threshold confirmation
76	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
77	
78	  // Deductible per damage event
79	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
80	
81	  // Cap behaviour
82	  it.todo("should cap total payout at twice the insurance sum");
83	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
84	
85	  // Rounding down in MHPCO's favor
86	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
87	
88	  // Error cases
89	  it.todo("should reject a claim whose damage entry references an item not in the policy");
90	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
91	  it.todo("should reject a claim with a negative damage amount");
92	});
